var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"차원터널을 막고 있는 원인을 찾아 파괴한다라...","JPN":"次元トンネルを塞いでいる原因を探して破壊する、ですか……","ENG":"So our objective is to find and destroy whatever is blocking the dimensional tunnel...","TWN":"找出並破壞堵住隧道的原因……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"결국, 이번 작전은 정면 돌파로군요.","JPN":"結局、今回の作戦は正面突破ですね。","ENG":"In the end, this operation is a direct breakthrough, then.","TWN":"結果這次作戰還是正面突破。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"더 똑똑한 방법이라도 있냐?","JPN":"もっとスマートな方法でもあるか？","ENG":"Do you have a smarter idea?","TWN":"你有更聰明的方法嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"전 머리보단 몸을 쓰는 쪽이라서요. 더 좋은 방법은 다른 분들께 맡기겠습니다.","JPN":"僕は頭よりは体を使う方ですので。もっといい方法は、他の方々にお任せしますよ。","ENG":"I'm more the type to use my body than my brain. I'll leave better ideas to the others.","TWN":"我比較擅長用身體，不太會用腦。更好的方法就交給別人吧。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"핵심 목표는 파노라마 회수입니다. 거울로 터널을 확장하지 못하면 타기리온의 하수인들을 몰아내도 의미가 없어요.","JPN":"主な目標はパノラマの回収です。鏡でトンネルを拡張できなければ、タギリオンの手先を追い払ったとしても意味がありません。","ENG":"Our primary objective is to retrieve the Panorama. If we can't expand the tunnel with the mirror, driving out Thagirion's minions won't mean anything.","TWN":"核心目標是回收全景。如果不能使用鏡子擴張隧道，就算擊退塔基里翁的部下也沒有意義。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그자라면 핵이 없는 인형 따위는, 얼마든지 만들어낼 수 있으니까요.","JPN":"あの者なら核のない人間など、いくらでも作れるのですから。","ENG":"She can produce as many coreless dolls as she wants.","TWN":"因為她隨時都能製造沒有內核的人偶。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"작전 내용이 잘 전달됐다면, 달님 팀에서도 차원터널에 핵심 전력을 보낼 겁니다.","JPN":"作戦内容がちゃんと伝わったなら、お月様チームも次元トンネルにメイン戦力を送るはずです。","ENG":"If the operation details were properly delivered, Team Moon will also deploy their main force into the dimensional tunnel.","TWN":"如果順利傳達作戰內容，月亮小隊應該也會派核心戰力到次元隧道。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"터널 중심에 자리 잡은 타기리온의 군세를 양쪽에서 압박하는 거죠.","JPN":"トンネルの中心に居座っているタギリオンの軍勢を、両端から圧迫することになりますね。","ENG":"They'll pressure Thagirion's army stationed at the center of the tunnel from both sides.","TWN":"從兩邊夾擊隧道中央的塔基里翁軍勢。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하지만 달님 팀의 최우선 목표는 과거의 코핀 오브 타기리온에서 파노라마를 회수하는 게 아닌가요?","JPN":"でも、お月様チームの最優先目標は過去のコフィン・オブ・タギリオンからパノラマを回収することですよね？","ENG":"But isn't Team Moon's top priority to retrieve the Panorama from the Coffin of Thagirion in the past?","TWN":"但月亮小隊的最優先目標，不是在過去的塔基里翁之棺回收全景嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"스승님과 미나 양, 노엘 양. 핵심 전력 중 하나라도 분산시키는 것보단, 차원터널 확보를 저희에게 맡기고 다 함께 움직이는 편이 나았을 것 같은데요.","JPN":"師匠とミナさん、ノエルさん。このメイン戦力を分散させるよりは、次元トンネルの確保は僕たちに任せて、まとまって動いてもらった方がいいと思いますが。","ENG":"Master, Mina, and Noelle. Rather than splitting even one of your key forces, wouldn't it have been better to leave securing the dimensional tunnel to us and move together as a group?","TWN":"師父、米娜、洛艾兒，與其分散核心戰力，不如把打通次元隧道交給我們，三個人一起行動不是更好嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말게. 세 사람은 함께 움직일 테니.","JPN":"心配する必要はない。3人は共に動くはずだからな。","ENG":"There's no need to worry. The three of them will move together.","TWN":"不用擔心，他們三個會一起行動。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"네? 그럼 핵심 전력이라고 하셨던 건...","JPN":"え？　では、メイン戦力というのは……","ENG":"Pardon? Then the key force you mentioned was...","TWN":"什麼？那你說的核心戰力是……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리실패로 어수선했던 그 시기에도, 세 사람 못지 않게 믿음직한 전력이 있거든.","JPN":"管理失敗で混乱していたあの頃も、3人に負けないくらい頼もしい戦力はいたからな。","ENG":"Even during that chaotic period caused by the Administration Failure, there was another force just as reliable as those three.","TWN":"在那個管理失序的時期，還有一個不輸他們三人的可靠戰力。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그래. 일이 이렇게 됐으니, 증폭터널 확보는 너에게 맡기마.","JPN":"そうだ。こうなった以上、増幅トンネルの確保はお前に任せよう。","ENG":"That's right. Since things turned out this way, I'll leave securing the amplification tunnel to you.","TWN":"好。事情既然變成這樣，確保增幅隧道就交給你了。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네, 맡겨주세요.","JPN":"はい、お任せください。","ENG":"Yes, please leave it to me.","TWN":"是，交給我吧。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다짜고짜 연화 씨한테 그렇게 위험한 일을 맡겨도 괜찮은 거야?","JPN":"いきなりレンカさんにそんなに危険なことを任せて大丈夫なの？","ENG":"Are you sure it's okay to suddenly leave something that dangerous to Yeonhwa?","TWN":"突然把這麼危險的任務交給蓮華，真的沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"터널을 막고 있는 건 침식체도 아니고 마왕의 부하들이라며?","JPN":"トンネルを塞いでるのは侵食体じゃなくて、魔王の部下たちなんでしょ？","ENG":"You said what's blocking the tunnel isn't a C.O. but the Demon Lord's subordinates, right?","TWN":"堵住隧道的可是魔王的部下耶？"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"...문제 없을 거다.","JPN":"……問題ないはずだ。","ENG":"...There won't be a problem.","TWN":"……沒問題。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"연화는 그런 녀석들을 상대하기 위해 지금껏 훈련을 거듭해온 거니까.","JPN":"レンカはそんなやつらを相手するために今まで訓練を重ねてきたんだからな。","ENG":"Yeonhwa has been training all this time precisely to deal with enemies like them.","TWN":"蓮華一直以來就是為了對付那些傢伙接受訓練。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"후후, 그럼요. 이래 봬도 스승님의 수제자니까, 걱정하지 마세요.","JPN":"ふふ、もちろんです。こう見えても師匠の一番弟子ですからね。心配しないでください。","ENG":"Haha, of course. I'm Master's top apprentice, after all, so don't worry.","TWN":"呵呵，當然囉。別看我這樣，我好歹也是師父的首席弟子耶？別擔心了。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ENGINEER_NPC_ADMIN_NULL","text":{"KOREA":"대우물이 버틸 수 있는 차원압이 임계치에 다다르고 있습니다!","JPN":"大イドが耐えられる次元圧が臨界寸前です！","ENG":"The dimensional pressure the Great Well can withstand is approaching its critical point!","TWN":"大井能承受的次元壓力已經接近臨界值！"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ENGINEER_NPC_ADMIN_NULL","text":{"KOREA":"통로를 막고 있는 원인을 제거하지 못하면, 차원터널이 곧 무너질 겁니다!","JPN":"通路を塞いでいる原因を取り除けなければ、もうすぐ次元トンネルが崩壊します！","ENG":"If we can't remove what's blocking the passage, the dimensional tunnel will collapse soon!","TWN":"如果不清除堵住通道的原因，次元隧道很快就會崩塌！"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"부담 갖지 말고 다녀오세요.","JPN":"こちらは気にせず、行ってください。","ENG":"Please go without worrying.","TWN":"不用有壓力，去吧。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"여러분이 겪게 될 고난은 저희가 감내해야 할 일이기도 하니까요.","JPN":"皆さんの苦難は、私たちが甘受すべきものでもあるんですから。","ENG":"The hardships you'll face are also something we must bear as well.","TWN":"你們即將承受的苦難，本來就也是我們應該承擔的。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그럼, 부탁할게.","JPN":"じゃあ、頼むね。","ENG":"Then I'm counting on you.","TWN":"那就拜託你們了。"},"stage":{"bg":"COUNTERSIDE_WELL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 차원 함선이다!","JPN":"あっ、次元艦船！","ENG":"Oh, it's a dimensional ship!","TWN":"啊，是次元艦船！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"예이-! 여기에요, 여기!","JPN":"わーい！　ここです、ここ！","ENG":"Yay! Over here, over here!","TWN":"耶—！在這裡，這裡！"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};